      "code": "class LRUCache {\nprivate:\n    struct Node {\n        int key, val;\n        Node* prev;\n        Node* next;\n        Node(int key, int val)\n            : key(key)\n            , val(val)\n            , prev(nullptr)\n            , next(nullptr) {}\n    };\n\n    int size;\n    int capacity;\n    Node* head;\n    Node* tail;\n    unordered_map<int, Node*> cache;\n\n    void removeNode(Node* node) {\n        node->prev->next = node->next;\n        node->next->prev = node->prev;\n    }\n\n    void addToHead(Node* node) {\n        node->next = head->next;\n        node->prev = head;\n        head->next->prev = node;\n        head->next = node;\n    }\n\npublic:\n    LRUCache(int capacity)\n        : size(0)\n        , capacity(capacity) {\n        head = new Node(0, 0);\n        tail = new Node(0, 0);\n        head->next = tail;\n        tail->prev = head;\n    }\n\n    int get(int key) {\n        if (!cache.contains(key)) {\n            return -1;\n        }\n        Node* node = cache[key];\n        removeNode(node);\n        addToHead(node);\n        return node->val;\n    }\n\n    void put(int key, int value) {\n        if (cache.contains(key)) {\n            Node* node = cache[key];\n            removeNode(node);\n            node->val = value;\n            addToHead(node);\n        } else {\n            Node* node = new Node(key, value);\n            cache[key] = node;\n            addToHead(node);\n            if (++size > capacity) {\n                node = tail->prev;\n                cache.erase(node->key);\n                removeNode(node);\n                --size;\n            }\n        }\n    }\n};\n\n/**\n * Your LRUCache object will be instantiated and called as such:\n * LRUCache* obj = new LRUCache(capacity);\n * int param_1 = obj->get(key);\n * obj->put(key,value);\n */"
