      "code": "struct Node {\n    int k;\n    int v;\n    Node* prev;\n    Node* next;\n\n    Node()\n        : k(0)\n        , v(0)\n        , prev(nullptr)\n        , next(nullptr) {}\n    Node(int key, int val)\n        : k(key)\n        , v(val)\n        , prev(nullptr)\n        , next(nullptr) {}\n};\n\nclass LRUCache {\npublic:\n    LRUCache(int capacity)\n        : cap(capacity)\n        , size(0) {\n        head = new Node();\n        tail = new Node();\n        head->next = tail;\n        tail->prev = head;\n    }\n\n    int get(int key) {\n        if (!cache.count(key)) return -1;\n        Node* node = cache[key];\n        moveToHead(node);\n        return node->v;\n    }\n\n    void put(int key, int value) {\n        if (cache.count(key)) {\n            Node* node = cache[key];\n            node->v = value;\n            moveToHead(node);\n        } else {\n            Node* node = new Node(key, value);\n            cache[key] = node;\n            addToHead(node);\n            ++size;\n            if (size > cap) {\n                node = removeTail();\n                cache.erase(node->k);\n                --size;\n            }\n        }\n    }\n\nprivate:\n    unordered_map<int, Node*> cache;\n    Node* head;\n    Node* tail;\n    int cap;\n    int size;\n\n    void moveToHead(Node* node) {\n        removeNode(node);\n        addToHead(node);\n    }\n\n    void removeNode(Node* node) {\n        node->prev->next = node->next;\n        node->next->prev = node->prev;\n    }\n\n    void addToHead(Node* node) {\n        node->next = head->next;\n        node->prev = head;\n        head->next = node;\n        node->next->prev = node;\n    }\n\n    Node* removeTail() {\n        Node* node = tail->prev;\n        removeNode(node);\n        return node;\n    }\n};\n\n/**\n * Your LRUCache object will be instantiated and called as such:\n * LRUCache* obj = new LRUCache(capacity);\n * int param_1 = obj->get(key);\n * obj->put(key,value);\n */"
