      "code": "class Solution {\npublic:\n    string longestPalindrome(string s) {\n        int n = s.size();\n        vector<vector<bool>> f(n, vector<bool>(n, true));\n        int k = 0, mx = 1;\n        for (int i = n - 2; ~i; --i) {\n            for (int j = i + 1; j < n; ++j) {\n                f[i][j] = false;\n                if (s[i] == s[j]) {\n                    f[i][j] = f[i + 1][j - 1];\n                    if (f[i][j] && mx < j - i + 1) {\n                        mx = j - i + 1;\n                        k = i;\n                    }\n                }\n            }\n        }\n        return s.substr(k, mx);\n    }\n};"
