      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Solution 3: Union-Find",
      "complexity": "Time is $O(m \\times n \\times \\log (m \\times n))$, and the space complexity is $O(m \\t / Space is $O(m \\times n)$",
