      "code": "class Solution {\npublic:\n    int findKthLargest(vector<int>& nums, int k) {\n        priority_queue<int, vector<int>, greater<int>> minQ;\n        for (int x : nums) {\n            minQ.push(x);\n            if (minQ.size() > k) {\n                minQ.pop();\n            }\n        }\n        return minQ.top();\n    }\n};"
