      "code": "class Solution {\npublic:\n    int findKthLargest(vector<int>& nums, int k) {\n        unordered_map<int, int> cnt;\n        int m = INT_MIN;\n        for (int x : nums) {\n            ++cnt[x];\n            m = max(m, x);\n        }\n        for (int i = m;; --i) {\n            k -= cnt[i];\n            if (k <= 0) {\n                return i;\n            }\n        }\n    }\n};"
