      "code": "class Solution {\npublic:\n    int sum(int num1, int num2) {\n        while (num2) {\n            unsigned int carry = (unsigned int) (num1 & num2) << 1;\n            num1 ^= num2;\n            num2 = carry;\n        }\n        return num1;\n    }\n};"
