      "code": "class Solution {\npublic:\n    vector<int> spiralOrder(vector<vector<int>>& matrix) {\n        int m = matrix.size(), n = matrix[0].size();\n        int dirs[5] = {0, 1, 0, -1, 0};\n        int i = 0, j = 0, k = 0;\n        vector<int> ans;\n        for (int h = m * n; h; --h) {\n            ans.push_back(matrix[i][j]);\n            matrix[i][j] += 300;\n            int x = i + dirs[k], y = j + dirs[k + 1];\n            if (x < 0 || x >= m || y < 0 || y >= n || matrix[x][y] > 100) {\n                k = (k + 1) % 4;\n            }\n            i += dirs[k];\n            j += dirs[k + 1];\n        }\n        for (i = 0; i < m; ++i) {\n            for (j = 0; j < n; ++j) {\n                matrix[i][j] -= 300;\n            }\n        }\n        return ans;\n    }\n};"
