      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0200-0299/0239.Sliding%20Window%20Maximum/README_EN.md",
      "code": "class Solution {\npublic:\n    vector<int> maxSlidingWindow(vector<int>& nums, int k) {\n        deque<int> q;\n        vector<int> ans;\n        for (int i = 0; i < nums.size(); ++i) {\n            if (q.size() && i - q.front() >= k) {\n                q.pop_front();\n            }\n            while (q.size() && nums[q.back()] <= nums[i]) {\n                q.pop_back();\n            }\n            q.push_back(i);\n            if (i >= k - 1) {\n                ans.push_back(nums[q.front()]);\n            }\n        }\n        return ans;\n    }\n};"
