      "code": "class Solution {\npublic:\n    vector<string> generateParenthesis(int n) {\n        vector<string> ans;\n        auto dfs = [&](this auto&& dfs, int l, int r, string t) -> void {\n            if (l > n || r > n || l < r) {\n                return;\n            }\n            if (l == n && r == n) {\n                ans.push_back(t);\n                return;\n            }\n            dfs(l + 1, r, t + \"(\");\n            dfs(l, r + 1, t + \")\");\n        };\n        dfs(0, 0, \"\");\n        return ans;\n    }\n};"
