      "code": "class Solution {\npublic:\n    vector<int> findAnagrams(string s, string p) {\n        int m = s.size(), n = p.size();\n        vector<int> ans;\n        if (m < n) {\n            return ans;\n        }\n        vector<int> cnt1(26);\n        for (char& c : p) {\n            ++cnt1[c - 'a'];\n        }\n        vector<int> cnt2(26);\n        for (int i = 0, j = 0; i < m; ++i) {\n            int k = s[i] - 'a';\n            ++cnt2[k];\n            while (cnt2[k] > cnt1[k]) {\n                --cnt2[s[j++] - 'a'];\n            }\n            if (i - j + 1 == n) {\n                ans.push_back(j);\n            }\n        }\n        return ans;\n    }\n};"
