      "code": "class Solution {\npublic:\n    vector<int> findAnagrams(string s, string p) {\n        int m = s.size();\n        int n = p.size();\n        vector<int> ans;\n        if (m < n) {\n            return ans;\n        }\n        vector<int> cnt1(26), cnt2(26);\n        for (int i = 0; i < n; ++i) {\n            ++cnt1[s[i] - 'a'];\n            ++cnt2[p[i] - 'a'];\n        }\n        if (cnt1 == cnt2) {\n            ans.push_back(0);\n        }\n        for (int i = n; i < m; ++i) {\n            ++cnt1[s[i] - 'a'];\n            --cnt1[s[i - n] - 'a'];\n            if (cnt1 == cnt2) {\n                ans.push_back(i - n + 1);\n            }\n        }\n        return ans;\n    }\n};"
