      "code": "class Solution {\npublic:\n    int rob(vector<int>& nums) {\n        int n = nums.size();\n        int f[n + 1];\n        memset(f, 0, sizeof(f));\n        f[1] = nums[0];\n        for (int i = 2; i <= n; ++i) {\n            f[i] = max(f[i - 1], f[i - 2] + nums[i - 1]);\n        }\n        return f[n];\n    }\n};"
