      "code": "class Solution {\npublic:\n    int numSquares(int n) {\n        int m = sqrt(n);\n        int f[m + 1][n + 1];\n        memset(f, 0x3f, sizeof(f));\n        f[0][0] = 0;\n        for (int i = 1; i <= m; ++i) {\n            for (int j = 0; j <= n; ++j) {\n                f[i][j] = f[i - 1][j];\n                if (j >= i * i) {\n                    f[i][j] = min(f[i][j], f[i][j - i * i] + 1);\n                }\n            }\n        }\n        return f[m][n];\n    }\n};"
