      "code": "class Solution {\npublic:\n    vector<int> dailyTemperatures(vector<int>& temperatures) {\n        int n = temperatures.size();\n        vector<int> ans(n);\n        stack<int> stk;\n        for (int i = 0; i < n; ++i) {\n            while (!stk.empty() && temperatures[stk.top()] < temperatures[i]) {\n                ans[stk.top()] = i - stk.top();\n                stk.pop();\n            }\n            stk.push(i);\n        }\n        return ans;\n    }\n};"
