      "sourceTitle": "Doocs 0416.Partition Equal Subset Sum Solution 2: Dynamic Programming (Space Optimization)",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0400-0499/0416.Partition%20Equal%20Subset%20Sum/README_EN.md",
      "code": "class Solution {\npublic:\n    bool canPartition(vector<int>& nums) {\n        int s = accumulate(nums.begin(), nums.end(), 0);\n        if (s % 2 == 1) {\n            return false;\n        }\n        int m = s >> 1;\n        bool f[m + 1];\n        memset(f, false, sizeof(f));\n        f[0] = true;\n        for (int& x : nums) {\n            for (int j = m; j >= x; --j) {\n                f[j] |= f[j - x];\n            }\n        }\n        return f[m];\n    }\n};"
