      "code": "class Solution {\npublic:\n    int minSubArrayLen(int target, vector<int>& nums) {\n        int l = 0, n = nums.size();\n        long long s = 0;\n        int ans = n + 1;\n        for (int r = 0; r < n; ++r) {\n            s += nums[r];\n            while (s >= target) {\n                ans = min(ans, r - l + 1);\n                s -= nums[l++];\n            }\n        }\n        return ans > n ? 0 : ans;\n    }\n};"
