      "code": "class Solution {\npublic:\n    int jump(vector<int>& nums) {\n        int ans = 0, mx = 0, last = 0;\n        for (int i = 0; i < nums.size() - 1; ++i) {\n            mx = max(mx, i + nums[i]);\n            if (last == i) {\n                ++ans;\n                last = mx;\n            }\n        }\n        return ans;\n    }\n};"
