      "code": "class Solution {\npublic:\n    int removeDuplicates(vector<int>& nums) {\n        int k = 0;\n        for (int x : nums) {\n            if (k == 0 || x != nums[k - 1]) {\n                nums[k++] = x;\n            }\n        }\n        return k;\n    }\n};"
