      "code": "class Solution {\npublic:\n    string mergeAlternately(string word1, string word2) {\n        int m = word1.size(), n = word2.size();\n        string ans;\n        for (int i = 0; i < m || i < n; ++i) {\n            if (i < m) ans += word1[i];\n            if (i < n) ans += word2[i];\n        }\n        return ans;\n    }\n};"
