      "code": "/**\n * Definition for singly-linked list.\n * struct ListNode {\n *     int val;\n *     ListNode *next;\n *     ListNode() : val(0), next(nullptr) {}\n *     ListNode(int x) : val(x), next(nullptr) {}\n *     ListNode(int x, ListNode *next) : val(x), next(next) {}\n * };\n */\nclass Solution {\npublic:\n    ListNode* sortList(ListNode* head) {\n        if (!head || !head->next) return head;\n        auto* slow = head;\n        auto* fast = head->next;\n        while (fast && fast->next) {\n            slow = slow->next;\n            fast = fast->next->next;\n        }\n        auto* t = slow->next;\n        slow->next = nullptr;\n        auto* l1 = sortList(head);\n        auto* l2 = sortList(t);\n        auto* dummy = new ListNode();\n        auto* cur = dummy;\n        while (l1 && l2) {\n            if (l1->val <= l2->val) {\n                cur->next = l1;\n                l1 = l1->next;\n            } else {\n                cur->next = l2;\n                l2 = l2->next;\n            }\n            cur = cur->next;\n        }\n        cur->next = l1 ? l1 : l2;\n        return dummy->next;\n    }\n};"
