      "code": "class Solution {\npublic:\n    int countSubstrings(string s) {\n        int ans = 0;\n        int n = s.size();\n        for (int k = 0; k < n * 2 - 1; ++k) {\n            int i = k / 2, j = (k + 1) / 2;\n            while (~i && j < n && s[i] == s[j]) {\n                ++ans;\n                --i;\n                ++j;\n            }\n        }\n        return ans;\n    }\n};"
