      "code": "class Solution {\npublic:\n    int countSubstrings(string s) {\n        int ans = 0;\n        int n = s.size();\n        auto f = [&](int i, int j) -> int {\n            int cnt = 0;\n            for (; i >= 0 && j < n && s[i] == s[j]; --i, ++j) {\n                ++cnt;\n            }\n            return cnt;\n        };\n        for (int i = 0; i < n; ++i) {\n            ans += f(i, i) + f(i, i + 1);\n        }\n        return ans;\n    }\n};"
