      "code": "/**\n * Definition for singly-linked list.\n * struct ListNode {\n *     int val;\n *     ListNode *next;\n *     ListNode(int x) : val(x), next(NULL) {}\n * };\n */\nclass Solution {\npublic:\n    bool hasCycle(ListNode* head) {\n        unordered_set<ListNode*> s;\n        for (; head; head = head->next) {\n            if (s.contains(head)) {\n                return true;\n            }\n            s.insert(head);\n        }\n        return false;\n    }\n};"
