      "code": "class Solution {\npublic:\n    bool canMakeArithmeticProgression(vector<int>& arr) {\n        sort(arr.begin(), arr.end());\n        int d = arr[1] - arr[0];\n        for (int i = 2; i < arr.size(); i++) {\n            if (arr[i] - arr[i - 1] != d) {\n                return false;\n            }\n        }\n        return true;\n    }\n};"
