      "code": "class Solution {\npublic:\n    int mySqrt(int x) {\n        int l = 0, r = x;\n        while (l < r) {\n            int mid = (l + r + 1ll) >> 1;\n            if (mid > x / mid) {\n                r = mid - 1;\n            } else {\n                l = mid;\n            }\n        }\n        return l;\n    }\n};"
