      "code": "class Solution {\npublic:\n    vector<vector<int>> permuteUnique(vector<int>& nums) {\n        ranges::sort(nums);\n        int n = nums.size();\n        vector<vector<int>> ans;\n        vector<int> t(n);\n        vector<bool> vis(n);\n        auto dfs = [&](this auto&& dfs, int i) {\n            if (i == n) {\n                ans.emplace_back(t);\n                return;\n            }\n            for (int j = 0; j < n; ++j) {\n                if (vis[j] || (j && nums[j] == nums[j - 1] && !vis[j - 1])) {\n                    continue;\n                }\n                t[i] = nums[j];\n                vis[j] = true;\n                dfs(i + 1);\n                vis[j] = false;\n            }\n        };\n        dfs(0);\n        return ans;\n    }\n};"
