      "code": "class Solution {\npublic:\n    int maxProfit(vector<int>& prices) {\n        int n = prices.size();\n        int f[n][2];\n        f[0][0] = -prices[0];\n        f[0][1] = 0;\n        for (int i = 1; i < n; ++i) {\n            f[i][0] = max(f[i - 1][0], f[i - 1][1] - prices[i]);\n            f[i][1] = max(f[i - 1][1], f[i - 1][0] + prices[i]);\n        }\n        return f[n - 1][1];\n    }\n};"
