      "code": "class Solution {\npublic:\n    int maxProfit(vector<int>& prices) {\n        int n = prices.size();\n        int f[2] = {-prices[0], 0};\n        for (int i = 1; i < n; ++i) {\n            int g[2];\n            g[0] = max(f[0], f[1] - prices[i]);\n            g[1] = max(f[1], f[0] + prices[i]);\n            f[0] = g[0], f[1] = g[1];\n        }\n        return f[1];\n    }\n};"
