      "code": "class Solution {\npublic:\n    int totalFruit(vector<int>& fruits) {\n        unordered_map<int, int> cnt;\n        int ans = 0;\n        for (int i = 0, j = 0; i < fruits.size(); ++i) {\n            int x = fruits[i];\n            ++cnt[x];\n            while (cnt.size() > 2) {\n                int y = fruits[j++];\n                if (--cnt[y] == 0) {\n                    cnt.erase(y);\n                }\n            }\n            ans = max(ans, i - j + 1);\n        }\n        return ans;\n    }\n};"
