      "code": "class Solution {\npublic:\n    vector<vector<int>> ans;\n    vector<int> candidates;\n    int target;\n\n    vector<vector<int>> combinationSum(vector<int>& candidates, int target) {\n        this->candidates = candidates;\n        this->target = target;\n        vector<int> t;\n        dfs(0, 0, t);\n        return ans;\n    }\n\n    void dfs(int s, int u, vector<int>& t) {\n        if (s == target) {\n            ans.push_back(t);\n            return;\n        }\n        if (s > target) return;\n        for (int i = u; i < candidates.size(); ++i) {\n            int c = candidates[i];\n            t.push_back(c);\n            dfs(s + c, i, t);\n            t.pop_back();\n        }\n    }\n};"
