      "code": "class Solution {\npublic:\n    int longestOnes(vector<int>& nums, int k) {\n        int l = 0, cnt = 0;\n        for (int x : nums) {\n            cnt += x ^ 1;\n            if (cnt > k) {\n                cnt -= nums[l++] ^ 1;\n            }\n        }\n        return nums.size() - l;\n    }\n};"
