      "code": "class Solution {\npublic:\n    vector<int> twoSum(vector<int>& numbers, int target) {\n        for (int i = 0, j = numbers.size() - 1;;) {\n            int x = numbers[i] + numbers[j];\n            if (x == target) {\n                return {i + 1, j + 1};\n            }\n            if (x < target) {\n                ++i;\n            } else {\n                --j;\n            }\n        }\n    }\n};"
