      "code": "class Solution {\npublic:\n    vector<int> smallestK(vector<int>& arr, int k) {\n        priority_queue<int> q;\n        for (int& v : arr) {\n            q.push(v);\n            if (q.size() > k) {\n                q.pop();\n            }\n        }\n        vector<int> ans;\n        while (q.size()) {\n            ans.push_back(q.top());\n            q.pop();\n        }\n        return ans;\n    }\n};"
