      "code": "class Solution {\npublic:\n    string reverseParentheses(string s) {\n        string stk;\n        for (char& c : s) {\n            if (c == ')') {\n                string t;\n                while (stk.back() != '(') {\n                    t.push_back(stk.back());\n                    stk.pop_back();\n                }\n                stk.pop_back();\n                stk += t;\n            } else {\n                stk.push_back(c);\n            }\n        }\n        return stk;\n    }\n};"
