      "code": "class Solution {\npublic:\n    string smallestSubsequence(string s) {\n        int n = s.size();\n        int last[26] = {0};\n        for (int i = 0; i < n; ++i) {\n            last[s[i] - 'a'] = i;\n        }\n        string ans;\n        int mask = 0;\n        for (int i = 0; i < n; ++i) {\n            char c = s[i];\n            if ((mask >> (c - 'a')) & 1) {\n                continue;\n            }\n            while (!ans.empty() && ans.back() > c && last[ans.back() - 'a'] > i) {\n                mask ^= 1 << (ans.back() - 'a');\n                ans.pop_back();\n            }\n            ans.push_back(c);\n            mask |= 1 << (c - 'a');\n        }\n        return ans;\n    }\n};"
