      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0100-0199/0188.Best%20Time%20to%20Buy%20and%20Sell%20Stock%20IV/README_EN.md",
      "code": "class Solution {\npublic:\n    int maxProfit(int k, vector<int>& prices) {\n        int n = prices.size();\n        int f[n][k + 1][2];\n        memset(f, 0, sizeof(f));\n        for (int j = 1; j <= k; ++j) {\n            f[0][j][1] = -prices[0];\n        }\n        for (int i = 1; i < n; ++i) {\n            for (int j = 1; j <= k; ++j) {\n                f[i][j][0] = max(f[i - 1][j][1] + prices[i], f[i - 1][j][0]);\n                f[i][j][1] = max(f[i - 1][j - 1][0] - prices[i], f[i - 1][j][1]);\n            }\n        }\n        return f[n - 1][k][0];\n    }\n};"
