      "code": "class Solution {\npublic:\n    int maxProfit(int k, vector<int>& prices) {\n        int n = prices.size();\n        int f[k + 1][2];\n        memset(f, 0, sizeof(f));\n        for (int j = 1; j <= k; ++j) {\n            f[j][1] = -prices[0];\n        }\n        for (int i = 1; i < n; ++i) {\n            for (int j = k; j; --j) {\n                f[j][0] = max(f[j][1] + prices[i], f[j][0]);\n                f[j][1] = max(f[j - 1][0] - prices[i], f[j][1]);\n            }\n        }\n        return f[k][0];\n    }\n};"
