  "kth-smallest-element-in-a-sorted-matrix": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time 下解决这个问题吗?这个方法对于面试来说可能太超前了，但是你会发现阅读这篇文章（&nbsp",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 0378.Kth Smallest Element in a Sorted Matrix Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0300-0399/0378.Kth%20Smallest%20Element%20in%20a%20Sorted%20Matrix/README.md",
      "code": "class Solution {\npublic:\n    int kthSmallest(vector<vector<int>>& matrix, int k) {\n        int n = matrix.size();\n        int left = matrix[0][0], right = matrix[n - 1][n - 1];\n        while (left < right) {\n            int mid = left + right >> 1;\n            if (check(matrix, mid, k, n)) {\n                right = mid;\n            } else {\n                left = mid + 1;\n            }\n        }\n        return left;\n    }\n\nprivate:\n    bool check(vector<vector<int>>& matrix, int mid, int k, int n) {\n        int count = 0;\n        int i = n - 1, j = 0;\n        while (i >= 0 && j < n) {\n            if (matrix[i][j] <= mid) {\n                count += (i + 1);\n                ++j;\n            } else {\n                --i;\n            }\n        }\n        return count >= k;\n    }\n};"
    }
  ],
