      "code": "class Solution {\npublic:\n    bool isSubsequence(string s, string t) {\n        int m = s.size(), n = t.size();\n        int i = 0, j = 0;\n        for (; i < m && j < n; ++j) {\n            if (s[i] == t[j]) {\n                ++i;\n            }\n        }\n        return i == m;\n    }\n};"
