      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Solution 2: Dynamic Programming",
      "complexity": "Time is $O(m \\times n)$, and the space complexity is $O(m \\times n)$ / Space is $O(m \\times n)$",
