      "code": "class Solution {\npublic:\n    int firstUniqChar(string s) {\n        int cnt[26]{};\n        for (char& c : s) {\n            ++cnt[c - 'a'];\n        }\n        int n = s.size();\n        for (int i = 0; i < n; ++i) {\n            if (cnt[s[i] - 'a'] == 1) {\n                return i;\n            }\n        }\n        return -1;\n    }\n};"
