      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}\n * };\n */\nclass Solution {\npublic:\n    bool isBalanced(TreeNode* root) {\n        function<int(TreeNode*)> dfs = [&](TreeNode* root) -> int {\n            if (!root) {\n                return 0;\n            }\n            int l = dfs(root->left);\n            int r = dfs(root->right);\n            if (l == -1 || r == -1 || abs(l - r) > 1) {\n                return -1;\n            }\n            return 1 + max(l, r);\n        };\n        return dfs(root) != -1;\n    }\n};"
