      "code": "class Solution {\npublic:\n    int hIndex(vector<int>& citations) {\n        int n = citations.size();\n        int cnt[n + 1];\n        memset(cnt, 0, sizeof(cnt));\n        for (int x : citations) {\n            ++cnt[min(x, n)];\n        }\n        for (int h = n, s = 0;; --h) {\n            s += cnt[h];\n            if (s >= h) {\n                return h;\n            }\n        }\n    }\n};"
