      "code": "class Solution {\npublic:\n    int singleNumber(vector<int>& nums) {\n        int ans = 0;\n        for (int i = 0; i < 32; ++i) {\n            int cnt = 0;\n            for (int num : nums) {\n                cnt += ((num >> i) & 1);\n            }\n            cnt %= 3;\n            ans |= cnt << i;\n        }\n        return ans;\n    }\n};"
