      "code": "class Solution {\npublic:\n    int singleNumber(vector<int>& nums) {\n        int a = 0, b = 0;\n        for (int c : nums) {\n            int aa = (~a & b & c) | (a & ~b & ~c);\n            int bb = ~a & (b ^ c);\n            a = aa;\n            b = bb;\n        }\n        return b;\n    }\n};"
