      "code": "class RandomizedSet {\npublic:\n    RandomizedSet() {\n    }\n\n    bool insert(int val) {\n        if (d.count(val)) {\n            return false;\n        }\n        d[val] = q.size();\n        q.push_back(val);\n        return true;\n    }\n\n    bool remove(int val) {\n        if (!d.count(val)) {\n            return false;\n        }\n        int i = d[val];\n        d[q.back()] = i;\n        q[i] = q.back();\n        q.pop_back();\n        d.erase(val);\n        return true;\n    }\n\n    int getRandom() {\n        return q[rand() % q.size()];\n    }\n\nprivate:\n    unordered_map<int, int> d;\n    vector<int> q;\n};\n\n/**\n * Your RandomizedSet object will be instantiated and called as such:\n * RandomizedSet* obj = new RandomizedSet();\n * bool param_1 = obj->insert(val);\n * bool param_2 = obj->remove(val);\n * int param_3 = obj->getRandom();\n */"
