      "code": "class Solution {\npublic:\n    bool isUgly(int n) {\n        if (n < 1) return false;\n        while (n % 2 == 0) {\n            n /= 2;\n        }\n        while (n % 3 == 0) {\n            n /= 3;\n        }\n        while (n % 5 == 0) {\n            n /= 5;\n        }\n        return n == 1;\n    }\n};"
