      "code": "class Solution {\npublic:\n    bool isPerfectSquare(int num) {\n        int l = 1, r = num;\n        while (l < r) {\n            int mid = l + (r - l) / 2;\n            if (1LL * mid * mid >= num) {\n                r = mid;\n            } else {\n                l = mid + 1;\n            }\n        }\n        return 1LL * l * l == num;\n    }\n};"
