      "code": "class Trie {\npublic:\n    vector<Trie*> children;\n    string v;\n    Trie()\n        : children(2) {}\n\n    void insert(int x) {\n        Trie* node = this;\n        for (int i = 30; ~i; --i) {\n            int v = (x >> i) & 1;\n            if (!node->children[v]) node->children[v] = new Trie();\n            node = node->children[v];\n        }\n    }\n\n    int search(int x) {\n        Trie* node = this;\n        int res = 0;\n        for (int i = 30; ~i; --i) {\n            int v = (x >> i) & 1;\n            if (node->children[v ^ 1]) {\n                res = res << 1 | 1;\n                node = node->children[v ^ 1];\n            } else {\n                res <<= 1;\n                node = node->children[v];\n            }\n        }\n        return res;\n    }\n};\n\nclass Solution {\npublic:\n    int findMaximumXOR(vector<int>& nums) {\n        Trie* trie = new Trie();\n        int ans = 0;\n        for (int v : nums) {\n            trie->insert(v);\n            ans = max(ans, trie->search(v));\n        }\n        return ans;\n    }\n};"
