      "code": "class Solution {\npublic:\n    bool validateStackSequences(vector<int>& pushed, vector<int>& popped) {\n        stack<int> stk;\n        int i = 0;\n        for (int x : pushed) {\n            stk.push(x);\n            while (stk.size() && stk.top() == popped[i]) {\n                stk.pop();\n                ++i;\n            }\n        }\n        return i == popped.size();\n    }\n};"
