      "code": "class Solution {\npublic:\n    string removeDuplicates(string s) {\n        string stk;\n        for (char c : s) {\n            if (!stk.empty() && stk[stk.size() - 1] == c) {\n                stk.pop_back();\n            } else {\n                stk += c;\n            }\n        }\n        return stk;\n    }\n};"
