      "code": "class Solution {\npublic:\n    int peakIndexInMountainArray(vector<int>& arr) {\n        int left = 1, right = arr.size() - 2;\n        while (left < right) {\n            int mid = (left + right) >> 1;\n            if (arr[mid] > arr[mid + 1])\n                right = mid;\n            else\n                left = mid + 1;\n        }\n        return left;\n    }\n};"
