      "code": "class Solution {\npublic:\n    int longestPalindrome(string s) {\n        int cnt[128]{};\n        for (char c : s) {\n            ++cnt[c];\n        }\n        int ans = 0;\n        for (int v : cnt) {\n            ans += v / 2 * 2;\n        }\n        ans += ans < s.size();\n        return ans;\n    }\n};"
