      "code": "class Solution {\npublic:\n    int maxProfit(vector<int>& prices, int fee) {\n        int n = prices.size();\n        int f[n][2];\n        memset(f, -1, sizeof(f));\n        function<int(int, int)> dfs = [&](int i, int j) {\n            if (i >= prices.size()) {\n                return 0;\n            }\n            if (f[i][j] != -1) {\n                return f[i][j];\n            }\n            int ans = dfs(i + 1, j);\n            if (j) {\n                ans = max(ans, prices[i] + dfs(i + 1, 0) - fee);\n            } else {\n                ans = max(ans, -prices[i] + dfs(i + 1, 1));\n            }\n            return f[i][j] = ans;\n        };\n        return dfs(0, 0);\n    }\n};"
