      "code": "class Solution {\npublic:\n    int maxProfit(vector<int>& prices, int fee) {\n        int f0 = 0, f1 = -prices[0];\n        for (int i = 1; i < prices.size(); ++i) {\n            int g0 = max(f0, f1 + prices[i] - fee);\n            f1 = max(f1, f0 - prices[i]);\n            f0 = g0;\n        }\n        return f0;\n    }\n};"
