      "code": "class Solution {\npublic:\n    double new21Game(int n, int k, int maxPts) {\n        vector<double> f(k);\n        auto dfs = [&](this auto&& dfs, int i) -> double {\n            if (i >= k) {\n                return i <= n ? 1 : 0;\n            }\n            if (i == k - 1) {\n                return min(n - k + 1, maxPts) * 1.0 / maxPts;\n            }\n            if (f[i]) {\n                return f[i];\n            }\n            return f[i] = dfs(i + 1) + (dfs(i + 1) - dfs(i + maxPts + 1)) / maxPts;\n        };\n        return dfs(0);\n    }\n};"
