      "code": "class Solution {\npublic:\n    int minPairSum(vector<int>& nums) {\n        ranges::sort(nums);\n        int ans = 0, n = nums.size();\n        for (int i = 0; i < n >> 1; ++i) {\n            ans = max(ans, nums[i] + nums[n - i - 1]);\n        }\n        return ans;\n    }\n};"
