  "maximum-side-length-of-a-square-with-sum-less-than-or-equal-to-threshold": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(m \\times n \\times \\log \\min(m, n))$，空间复杂度 $O(m \\times n)$ / Space $O(m \\times n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1292.Maximum Side Length of a Square with Sum Less than or Equal to Threshold Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1200-1299/1292.Maximum%20Side%20Length%20of%20a%20Square%20with%20Sum%20Less%20than%20or%20Equal%20to%20Threshold/README.md",
      "code": "class Solution {\npublic:\n    int maxSideLength(vector<vector<int>>& mat, int threshold) {\n        int m = mat.size(), n = mat[0].size();\n        int s[m + 1][n + 1];\n        memset(s, 0, sizeof(s));\n        for (int i = 1; i <= m; ++i) {\n            for (int j = 1; j <= n; ++j) {\n                s[i][j] = s[i - 1][j] + s[i][j - 1] - s[i - 1][j - 1] + mat[i - 1][j - 1];\n            }\n        }\n        auto check = [&](int k) {\n            for (int i = 0; i < m - k + 1; ++i) {\n                for (int j = 0; j < n - k + 1; ++j) {\n                    if (s[i + k][j + k] - s[i][j + k] - s[i + k][j] + s[i][j] <= threshold) {\n                        return true;\n                    }\n                }\n            }\n            return false;\n        };\n        int l = 0, r = min(m, n);\n        while (l < r) {\n            int mid = (l + r + 1) >> 1;\n            if (check(mid)) {\n                l = mid;\n            } else {\n                r = mid - 1;\n            }\n        }\n        return l;\n    }\n};"
    }
  ],
