      "code": "class Solution {\npublic:\n    long long maximumAlternatingSubarraySum(vector<int>& nums) {\n        using ll = long long;\n        const ll inf = 1LL << 60;\n        ll ans = -inf, f = -inf, g = -inf;\n        for (int x : nums) {\n            ll ff = max(g, 0LL) + x;\n            g = f - x;\n            f = ff;\n            ans = max({ans, f, g});\n        }\n        return ans;\n    }\n};"
