  "count-the-number-of-good-subsequences": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n \\times C)$，空间复杂度 $O(n)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 2539.Count the Number of Good Subsequences Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/2500-2599/2539.Count%20the%20Number%20of%20Good%20Subsequences/README.md",
      "code": "int N = 10001;\nint MOD = 1e9 + 7;\nlong f[10001];\nlong g[10001];\n\nlong qmi(long a, long k, long p) {\n    long res = 1;\n    while (k != 0) {\n        if ((k & 1) == 1) {\n            res = res * a % p;\n        }\n        k >>= 1;\n        a = a * a % p;\n    }\n    return res;\n}\n\nint init = []() {\n    f[0] = 1;\n    g[0] = 1;\n    for (int i = 1; i < N; ++i) {\n        f[i] = f[i - 1] * i % MOD;\n        g[i] = qmi(f[i], MOD - 2, MOD);\n    }\n    return 0;\n}();\n\nint comb(int n, int k) {\n    return (f[n] * g[k] % MOD) * g[n - k] % MOD;\n}\n\nclass Solution {\npublic:\n    int countGoodSubsequences(string s) {\n        int cnt[26]{};\n        int mx = 1;\n        for (char& c : s) {\n            mx = max(mx, ++cnt[c - 'a']);\n        }\n        long ans = 0;\n        for (int i = 1; i <= mx; ++i) {\n            long x = 1;\n            for (int j = 0; j < 26; ++j) {\n                if (cnt[j] >= i) {\n                    x = (x * (comb(cnt[j], i) + 1)) % MOD;\n                }\n            }\n            ans = (ans + x - 1) % MOD;\n        }\n        return ans;\n    }\n};"
    }
  ],
