      "code": "class Solution {\npublic:\n    vector<int> intersect(vector<int>& nums1, vector<int>& nums2) {\n        unordered_map<int, int> cnt;\n        for (int x : nums1) {\n            ++cnt[x];\n        }\n        vector<int> ans;\n        for (int x : nums2) {\n            if (cnt[x]-- > 0) {\n                ans.push_back(x);\n            }\n        }\n        return ans;\n    }\n};"
