      "code": "class Solution {\npublic:\n    vector<string> commonChars(vector<string>& words) {\n        vector<int> cnt(26, 20000);\n        for (const auto& w : words) {\n            vector<int> t(26, 0);\n            for (char c : w) {\n                ++t[c - 'a'];\n            }\n            for (int i = 0; i < 26; ++i) {\n                cnt[i] = min(cnt[i], t[i]);\n            }\n        }\n        vector<string> ans;\n        for (int i = 0; i < 26; ++i) {\n            for (int j = 0; j < cnt[i]; ++j) {\n                ans.push_back(string(1, 'a' + i));\n            }\n        }\n        return ans;\n    }\n};"
