  "delete-nodes-and-return-forest": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n)$，空间复杂度 $O(n)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1110.Delete Nodes And Return Forest Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1100-1199/1110.Delete%20Nodes%20And%20Return%20Forest/README.md",
      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:\n    vector<TreeNode*> delNodes(TreeNode* root, vector<int>& to_delete) {\n        bool s[1001];\n        memset(s, 0, sizeof(s));\n        for (int x : to_delete) {\n            s[x] = true;\n        }\n        vector<TreeNode*> ans;\n        function<TreeNode*(TreeNode*)> dfs = [&](TreeNode* root) -> TreeNode* {\n            if (!root) {\n                return nullptr;\n            }\n            root->left = dfs(root->left);\n            root->right = dfs(root->right);\n            if (!s[root->val]) {\n                return root;\n            }\n            if (root->left) {\n                ans.push_back(root->left);\n            }\n            if (root->right) {\n                ans.push_back(root->right);\n            }\n            return nullptr;\n        };\n        if (dfs(root)) {\n            ans.push_back(root);\n        }\n        return ans;\n    }\n};"
    }
  ],
  "design-a-stack-with-increment-operation": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(1)$，空间复杂度 $O(n)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1381.Design a Stack With Increment Operation Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1300-1399/1381.Design%20a%20Stack%20With%20Increment%20Operation/README.md",
      "code": "class CustomStack {\npublic:\n    CustomStack(int maxSize) {\n        stk.resize(maxSize);\n        add.resize(maxSize);\n        i = 0;\n    }\n\n    void push(int x) {\n        if (i < stk.size()) {\n            stk[i++] = x;\n        }\n    }\n\n    int pop() {\n        if (i <= 0) {\n            return -1;\n        }\n        int ans = stk[--i] + add[i];\n        if (i > 0) {\n            add[i - 1] += add[i];\n        }\n        add[i] = 0;\n        return ans;\n    }\n\n    void increment(int k, int val) {\n        if (i > 0) {\n            add[min(k, i) - 1] += val;\n        }\n    }\n\nprivate:\n    vector<int> stk;\n    vector<int> add;\n    int i;\n};\n\n/**\n * Your CustomStack object will be instantiated and called as such:\n * CustomStack* obj = new CustomStack(maxSize);\n * obj->push(x);\n * int param_2 = obj->pop();\n * obj->increment(k,val);\n */"
    }
  ],
  "count-sub-islands": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(m \\times n)$，空间复杂度 $O(m \\times n)$ / Space $O(m \\times n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1905.Count Sub Islands Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1900-1999/1905.Count%20Sub%20Islands/README.md",
      "code": "class Solution {\npublic:\n    int countSubIslands(vector<vector<int>>& grid1, vector<vector<int>>& grid2) {\n        int m = grid1.size(), n = grid1[0].size();\n        int ans = 0;\n        int dirs[5] = {-1, 0, 1, 0, -1};\n        function<int(int, int)> dfs = [&](int i, int j) {\n            int ok = grid1[i][j];\n            grid2[i][j] = 0;\n            for (int k = 0; k < 4; ++k) {\n                int x = i + dirs[k], y = j + dirs[k + 1];\n                if (x >= 0 && x < m && y >= 0 && y < n && grid2[x][y]) {\n                    ok &= dfs(x, y);\n                }\n            }\n            return ok;\n        };\n        for (int i = 0; i < m; ++i) {\n            for (int j = 0; j < n; ++j) {\n                if (grid2[i][j]) {\n                    ans += dfs(i, j);\n                }\n            }\n        }\n        return ans;\n    }\n};"
    }
  ],
