      "code": "class Solution {\npublic:\n    bool canPermutePalindrome(string s) {\n        unordered_map<char, int> cnt;\n        for (auto& c : s) {\n            ++cnt[c];\n        }\n        int sum = 0;\n        for (auto& [_, v] : cnt) {\n            sum += v & 1;\n        }\n        return sum < 2;\n    }\n};"
