  "insertion-sort-list": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Modern C++ reference",
      "complexity": null,
      "license": "MIT",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "kamyu104 C++/insertion-sort-list.cpp",
      "sourceUrl": "https://github.com/kamyu104/LeetCode-Solutions/blob/master/C%2B%2B/insertion-sort-list.cpp",
      "code": "// Time:  O(n^2)\n// Space: O(1)\n\n/**\n * Definition for singly-linked list.\n * struct ListNode {\n *     int val;\n *     ListNode *next;\n *     ListNode(int x) : val(x), next(NULL) {}\n * };\n */\nclass Solution {\n    public:\n        ListNode *insertionSortList(ListNode *head) {\n        ListNode dummy{numeric_limits<int>::min()};\n\n        auto curr = head;\n        ListNode *position = nullptr;\n\n        while (curr) {\n            position = findInsertPosition(&dummy, curr->val);\n            ListNode *tmp = curr->next;\n            curr->next = position->next;\n            position->next = curr;\n            curr = tmp;\n        }\n\n        return dummy.next;\n    }\n\n    ListNode* findInsertPosition(ListNode *head, int x) {\n        ListNode *prev = nullptr;\n        for (auto curr = head; curr && curr->val <= x;\n             prev = curr, curr = curr->next);\n        return prev;\n    }\n};"
    }
  ],
