      "code": "class Solution {\npublic:\n    int countPrimes(int n) {\n        vector<bool> primes(n, true);\n        int ans = 0;\n        for (int i = 2; i < n; ++i) {\n            if (primes[i]) {\n                ++ans;\n                for (int j = i; j < n; j += i) primes[j] = false;\n            }\n        }\n        return ans;\n    }\n};"
