  "divide-an-array-into-subarrays-with-minimum-cost-ii": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n \\times \\log \\textit{dist})$，空间复杂度 $O(\\textit{dist})$ / Space $O(\\textit{dist})$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 3013.Divide an Array Into Subarrays With Minimum Cost II Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/3000-3099/3013.Divide%20an%20Array%20Into%20Subarrays%20With%20Minimum%20Cost%20II/README.md",
      "code": "class Solution {\npublic:\n    long long minimumCost(vector<int>& nums, int k, int dist) {\n        --k;\n        multiset<int> l(nums.begin() + 1, nums.begin() + dist + 2), r;\n        long long s = accumulate(nums.begin(), nums.begin() + dist + 2, 0LL);\n        while (l.size() > k) {\n            int x = *l.rbegin();\n            l.erase(l.find(x));\n            s -= x;\n            r.insert(x);\n        }\n        long long ans = s;\n        for (int i = dist + 2; i < nums.size(); ++i) {\n            int x = nums[i - dist - 1];\n            auto it = l.find(x);\n            if (it != l.end()) {\n                l.erase(it);\n                s -= x;\n            } else {\n                r.erase(r.find(x));\n            }\n            int y = nums[i];\n            if (y < *l.rbegin()) {\n                l.insert(y);\n                s += y;\n            } else {\n                r.insert(y);\n            }\n            while (l.size() == k - 1) {\n                int x = *r.begin();\n                r.erase(r.find(x));\n                l.insert(x);\n                s += x;\n            }\n            while (l.size() == k + 1) {\n                int x = *l.rbegin();\n                l.erase(l.find(x));\n                s -= x;\n                r.insert(x);\n            }\n            ans = min(ans, s);\n        }\n        return ans;\n    }\n};"
    }
  ],
  "evaluate-division": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": null,
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 0399.Evaluate Division Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0300-0399/0399.Evaluate%20Division/README.md",
      "code": "class Solution {\npublic:\n    unordered_map<string, string> p;\n    unordered_map<string, double> w;\n\n    vector<double> calcEquation(vector<vector<string>>& equations, vector<double>& values, vector<vector<string>>& queries) {\n        int n = equations.size();\n        for (auto e : equations) {\n            p[e[0]] = e[0];\n            p[e[1]] = e[1];\n            w[e[0]] = 1.0;\n            w[e[1]] = 1.0;\n        }\n        for (int i = 0; i < n; ++i) {\n            vector<string> e = equations[i];\n            string a = e[0], b = e[1];\n            string pa = find(a), pb = find(b);\n            if (pa == pb) continue;\n            p[pa] = pb;\n            w[pa] = w[b] * values[i] / w[a];\n        }\n        int m = queries.size();\n        vector<double> ans(m);\n        for (int i = 0; i < m; ++i) {\n            string c = queries[i][0], d = queries[i][1];\n            ans[i] = p.find(c) == p.end() || p.find(d) == p.end() || find(c) != find(d) ? -1.0 : w[c] / w[d];\n        }\n        return ans;\n    }\n\n    string find(string x) {\n        if (p[x] != x) {\n            string origin = p[x];\n            p[x] = find(p[x]);\n            w[x] *= w[origin];\n        }\n        return p[x];\n    }\n};"
    },
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": null,
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 剑指 Offer II 111. 计算除法 Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/lcof2/%E5%89%91%E6%8C%87%20Offer%20II%20111.%20%E8%AE%A1%E7%AE%97%E9%99%A4%E6%B3%95/README.md",
      "code": "class Solution {\npublic:\n    vector<int> p;\n    vector<double> w;\n\n    vector<double> calcEquation(vector<vector<string>>& equations, vector<double>& values, vector<vector<string>>& queries) {\n        int n = equations.size();\n        for (int i = 0; i < (n << 1); ++i) {\n            p.push_back(i);\n            w.push_back(1.0);\n        }\n        unordered_map<string, int> mp;\n        int idx = 0;\n        for (int i = 0; i < n; ++i) {\n            auto e = equations[i];\n            string a = e[0], b = e[1];\n            if (mp.find(a) == mp.end()) mp[a] = idx++;\n            if (mp.find(b) == mp.end()) mp[b] = idx++;\n            int pa = find(mp[a]), pb = find(mp[b]);\n            if (pa == pb) continue;\n            p[pa] = pb;\n            w[pa] = w[mp[b]] * values[i] / w[mp[a]];\n        }\n        int m = queries.size();\n        vector<double> res;\n        for (int i = 0; i < m; ++i) {\n            string c = queries[i][0], d = queries[i][1];\n            if (mp.find(c) == mp.end() || mp.find(d) == mp.end())\n                res.push_back(-1.0);\n            else {\n                int pa = find(mp[c]), pb = find(mp[d]);\n                res.push_back(pa == pb ? w[mp[c]] / w[mp[d]] : -1.0);\n            }\n        }\n        return res;\n    }\n\n    int find(int x) {\n        if (p[x] != x) {\n            int origin = p[x];\n            p[x] = find(p[x]);\n            w[x] *= w[origin];\n        }\n        return p[x];\n    }\n};"
    }
  ],
