      "code": "class Solution {\npublic:\n    int numRescueBoats(vector<int>& people, int limit) {\n        sort(people.begin(), people.end());\n        int ans = 0;\n        for (int i = 0, j = people.size() - 1; i <= j; --j) {\n            if (people[i] + people[j] <= limit) {\n                ++i;\n            }\n            ++ans;\n        }\n        return ans;\n    }\n};"
