      "sourceTitle": "Doocs 0429.N-ary Tree Level Order Traversal Solution 2: DFS",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0400-0499/0429.N-ary%20Tree%20Level%20Order%20Traversal/README_EN.md",
      "code": "/*\n// Definition for a Node.\nclass Node {\npublic:\n    int val;\n    vector<Node*> children;\n\n    Node() {}\n\n    Node(int _val) {\n        val = _val;\n    }\n\n    Node(int _val, vector<Node*> _children) {\n        val = _val;\n        children = _children;\n    }\n};\n*/\n\nclass Solution {\npublic:\n    vector<vector<int>> levelOrder(Node* root) {\n        vector<vector<int>> ans;\n        function<void(Node*, int i)> dfs = [&](Node* root, int i) {\n            if (!root) {\n                return;\n            }\n            if (ans.size() <= i) {\n                ans.push_back({});\n            }\n            ans[i++].push_back(root->val);\n            for (auto& child : root->children) {\n                dfs(child, i);\n            }\n        };\n        dfs(root, 0);\n        return ans;\n    }\n};"
