  "maximum-profit-from-trading-stocks-with-discounts": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n \\times \\text{budget}^2)$，空间复杂度 $O(n \\times \\text{budget})$ / Space $O(n \\times \\text{budget})$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 3562.Maximum Profit from Trading Stocks with Discounts Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/3500-3599/3562.Maximum%20Profit%20from%20Trading%20Stocks%20with%20Discounts/README.md",
      "code": "class Solution {\npublic:\n    int maxProfit(int n, vector<int>& present, vector<int>& future, vector<vector<int>>& hierarchy, int budget) {\n        vector<vector<int>> g(n + 1);\n        for (auto& e : hierarchy) {\n            g[e[0]].push_back(e[1]);\n        }\n\n        auto dfs = [&](const auto& dfs, int u) -> vector<array<int, 2>> {\n            vector<array<int, 2>> nxt(budget + 1);\n            for (int j = 0; j <= budget; j++) nxt[j] = {0, 0};\n\n            for (int v : g[u]) {\n                auto fv = dfs(dfs, v);\n                for (int j = budget; j >= 0; j--) {\n                    for (int jv = 0; jv <= j; jv++) {\n                        for (int pre = 0; pre < 2; pre++) {\n                            int val = nxt[j - jv][pre] + fv[jv][pre];\n                            if (val > nxt[j][pre]) {\n                                nxt[j][pre] = val;\n                            }\n                        }\n                    }\n                }\n            }\n\n            vector<array<int, 2>> f(budget + 1);\n            int price = future[u - 1];\n\n            for (int j = 0; j <= budget; j++) {\n                for (int pre = 0; pre < 2; pre++) {\n                    int cost = present[u - 1] / (pre + 1);\n                    if (j >= cost) {\n                        f[j][pre] = max(nxt[j][0], nxt[j - cost][1] + (price - cost));\n                    } else {\n                        f[j][pre] = nxt[j][0];\n                    }\n                }\n            }\n\n            return f;\n        };\n\n        return dfs(dfs, 1)[budget][0];\n    }\n};"
    }
  ],
