      "code": "class Solution {\npublic:\n    bool canVisitAllRooms(vector<vector<int>>& rooms) {\n        int n = rooms.size();\n        int cnt = 0;\n        bool vis[n];\n        memset(vis, false, sizeof(vis));\n        function<void(int)> dfs = [&](int i) {\n            if (vis[i]) {\n                return;\n            }\n            vis[i] = true;\n            ++cnt;\n            for (int j : rooms[i]) {\n                dfs(j);\n            }\n        };\n        dfs(0);\n        return cnt == n;\n    }\n};"
