      "code": "class Solution {\npublic:\n    bool canVisitAllRooms(vector<vector<int>>& rooms) {\n        int n = rooms.size();\n        vector<bool> vis(n);\n        queue<int> q{{0}};\n        int cnt = 0;\n        while (q.size()) {\n            int i = q.front();\n            q.pop();\n            if (vis[i]) {\n                continue;\n            }\n            vis[i] = true;\n            ++cnt;\n            for (int j : rooms[i]) {\n                q.push(j);\n            }\n        }\n        return cnt == n;\n    }\n};"
