  "minimum-moves-to-move-a-box-to-their-target-location": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(m^2 \\times n^2)$，空间复杂度 $O(m^2 \\times n^2)$ / Space $O(m^2 \\times n^2)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1263.Minimum Moves to Move a Box to Their Target Location Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1200-1299/1263.Minimum%20Moves%20to%20Move%20a%20Box%20to%20Their%20Target%20Location/README.md",
      "code": "class Solution {\npublic:\n    int minPushBox(vector<vector<char>>& grid) {\n        int m = grid.size(), n = grid[0].size();\n        int si, sj, bi, bj;\n        for (int i = 0; i < m; ++i) {\n            for (int j = 0; j < n; ++j) {\n                if (grid[i][j] == 'S') {\n                    si = i, sj = j;\n                } else if (grid[i][j] == 'B') {\n                    bi = i, bj = j;\n                }\n            }\n        }\n        auto f = [&](int i, int j) {\n            return i * n + j;\n        };\n        auto check = [&](int i, int j) {\n            return i >= 0 && i < m && j >= 0 && j < n && grid[i][j] != '#';\n        };\n        int dirs[5] = {-1, 0, 1, 0, -1};\n        deque<tuple<int, int, int>> q;\n        q.emplace_back(f(si, sj), f(bi, bj), 0);\n        bool vis[m * n][m * n];\n        memset(vis, false, sizeof(vis));\n        vis[f(si, sj)][f(bi, bj)] = true;\n        while (!q.empty()) {\n            auto [s, b, d] = q.front();\n            q.pop_front();\n            si = s / n, sj = s % n;\n            bi = b / n, bj = b % n;\n            if (grid[bi][bj] == 'T') {\n                return d;\n            }\n            for (int k = 0; k < 4; ++k) {\n                int sx = si + dirs[k], sy = sj + dirs[k + 1];\n                if (!check(sx, sy)) {\n                    continue;\n                }\n                if (sx == bi && sy == bj) {\n                    int bx = bi + dirs[k], by = bj + dirs[k + 1];\n                    if (!check(bx, by) || vis[f(sx, sy)][f(bx, by)]) {\n                        continue;\n                    }\n                    vis[f(sx, sy)][f(bx, by)] = true;\n                    q.emplace_back(f(sx, sy), f(bx, by), d + 1);\n                } else if (!vis[f(sx, sy)][f(bi, bj)]) {\n                    vis[f(sx, sy)][f(bi, bj)] = true;\n                    q.emplace_front(f(sx, sy), f(bi, bj), d);\n                }\n            }\n        }\n        return -1;\n    }\n};"
    }
  ],
