  "minimum-cost-to-convert-string-ii": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(m^3 + n^2 + m \\times n)$，空间复杂度 $O(m^2 + m \\times n + n)$ / Space $O(m^2 + m \\times n + n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 2977.Minimum Cost to Convert String II Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/2900-2999/2977.Minimum%20Cost%20to%20Convert%20String%20II/README.md",
      "code": "class Node {\npublic:\n    Node* children[26];\n    int v = -1;\n    Node() {\n        fill(children, children + 26, nullptr);\n    }\n};\n\nclass Solution {\nprivate:\n    const long long inf = 1LL << 60;\n    Node* root = new Node();\n    int idx;\n\n    vector<vector<long long>> g;\n    string s;\n    string t;\n    vector<long long> f;\n\npublic:\n    long long minimumCost(string source, string target, vector<string>& original, vector<string>& changed, vector<int>& cost) {\n        int m = cost.size();\n        g = vector<vector<long long>>(m << 1, vector<long long>(m << 1, inf));\n        s = source;\n        t = target;\n\n        for (int i = 0; i < g.size(); ++i) {\n            g[i][i] = 0;\n        }\n\n        for (int i = 0; i < m; ++i) {\n            int x = insert(original[i]);\n            int y = insert(changed[i]);\n            g[x][y] = min(g[x][y], static_cast<long long>(cost[i]));\n        }\n\n        for (int k = 0; k < idx; ++k) {\n            for (int i = 0; i < idx; ++i) {\n                if (g[i][k] >= inf) {\n                    continue;\n                }\n                for (int j = 0; j < idx; ++j) {\n                    g[i][j] = min(g[i][j], g[i][k] + g[k][j]);\n                }\n            }\n        }\n\n        f = vector<long long>(s.length(), -1);\n        long long ans = dfs(0);\n        return ans >= inf ? -1 : ans;\n    }\n\nprivate:\n    int insert(const string& w) {\n        Node* node = root;\n        for (char c : w) {\n            int i = c - 'a';\n            if (node->children[i] == nullptr) {\n                node->children[i] = new Node();\n            }\n            node = node->children[i];\n        }\n        if (node->v < 0) {\n            node->v = idx++;\n        }\n        return node->v;\n    }\n\n    long long dfs(int i) {\n        if (i >= s.length()) {\n            return 0;\n        }\n        if (f[i] != -1) {\n            return f[i];\n        }\n        long long res = (s[i] == t[i]) ? dfs(i + 1) : inf;\n        Node* p = root;\n        Node* q = root;\n        for (int j = i; j < s.length(); ++j) {\n            p = p->children[s[j] - 'a'];\n            q = q->children[t[j] - 'a'];\n            if (p == nullptr || q == nullptr) {\n                break;\n            }\n            if (p->v < 0 || q->v < 0) {\n                continue;\n            }\n            long long temp = g[p->v][q->v];\n            if (temp < inf) {\n                res = min(res, temp + dfs(j + 1));\n            }\n        }\n        return f[i] = res;\n    }\n};"
    }
  ],
  "minimum-operations-to-make-median-of-array-equal-to-k": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n \\times \\log n)$，空间复杂度 $O(\\log n)$ / Space $O(\\log n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 3107.Minimum Operations to Make Median of Array Equal to K Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/3100-3199/3107.Minimum%20Operations%20to%20Make%20Median%20of%20Array%20Equal%20to%20K/README.md",
      "code": "class Solution {\npublic:\n    long long minOperationsToMakeMedianK(vector<int>& nums, int k) {\n        sort(nums.begin(), nums.end());\n        int n = nums.size();\n        int m = n >> 1;\n        long long ans = abs(nums[m] - k);\n        if (nums[m] > k) {\n            for (int i = m - 1; i >= 0 && nums[i] > k; --i) {\n                ans += nums[i] - k;\n            }\n        } else {\n            for (int i = m + 1; i < n && nums[i] < k; ++i) {\n                ans += k - nums[i];\n            }\n        }\n        return ans;\n    }\n};"
    }
  ],
