      "code": "class Solution {\npublic:\n    int minimumCost(vector<int>& nums) {\n        int a = nums[0], b = 100, c = 100;\n        for (int i = 1; i < nums.size(); ++i) {\n            if (nums[i] < b) {\n                c = b;\n                b = nums[i];\n            } else if (nums[i] < c) {\n                c = nums[i];\n            }\n        }\n        return a + b + c;\n    }\n};"
