      "code": "class Solution {\npublic:\n    int minimumSubstringsInPartition(string s) {\n        int n = s.size();\n        int f[n];\n        memset(f, -1, sizeof(f));\n        auto dfs = [&](this auto&& dfs, int i) -> int {\n            if (i >= n) {\n                return 0;\n            }\n            if (f[i] != -1) {\n                return f[i];\n            }\n            f[i] = n - i;\n            int cnt[26]{};\n            int k = 0, m = 0;\n            for (int j = i; j < n; ++j) {\n                k += ++cnt[s[j] - 'a'] == 1 ? 1 : 0;\n                m = max(m, cnt[s[j] - 'a']);\n                if (j - i + 1 == k * m) {\n                    f[i] = min(f[i], 1 + dfs(j + 1));\n                }\n            }\n            return f[i];\n        };\n        return dfs(0);\n    }\n};"
