      "code": "class Solution {\npublic:\n    int minimumSubstringsInPartition(string s) {\n        int n = s.size();\n        vector<int> f(n + 1, n);\n        f[0] = 0;\n        for (int i = 0; i < n; ++i) {\n            int cnt[26]{};\n            int k = 0, m = 0;\n            for (int j = i; ~j; --j) {\n                k += ++cnt[s[j] - 'a'] == 1;\n                m = max(m, cnt[s[j] - 'a']);\n                if (i - j + 1 == k * m) {\n                    f[i + 1] = min(f[i + 1], f[j] + 1);\n                }\n            }\n        }\n        return f[n];\n    }\n};"
