      "code": "class Solution {\npublic:\n    bool checkStrings(string s1, string s2) {\n        vector<vector<int>> cnt(2, vector<int>(26, 0));\n        for (int i = 0; i < s1.size(); ++i) {\n            ++cnt[i & 1][s1[i] - 'a'];\n            --cnt[i & 1][s2[i] - 'a'];\n        }\n        for (int i = 0; i < 26; ++i) {\n            if (cnt[0][i] || cnt[1][i]) {\n                return false;\n            }\n        }\n        return true;\n    }\n};"
