      "code": "class Solution {\npublic:\n    bool isNStraightHand(vector<int>& hand, int groupSize) {\n        if (hand.size() % groupSize) {\n            return false;\n        }\n        ranges::sort(hand);\n        unordered_map<int, int> cnt;\n        for (int x : hand) {\n            ++cnt[x];\n        }\n        for (int x : hand) {\n            if (cnt.contains(x)) {\n                for (int y = x; y < x + groupSize; ++y) {\n                    if (!cnt.contains(y)) {\n                        return false;\n                    }\n                    if (--cnt[y] == 0) {\n                        cnt.erase(y);\n                    }\n                }\n            }\n        }\n        return true;\n    }\n};"
