      "code": "class Solution {\npublic:\n    int minimumDifference(vector<int>& nums, int k) {\n        sort(nums.begin(), nums.end());\n        int ans = 1e5;\n        for (int i = 0; i < nums.size() - k + 1; ++i) {\n            ans = min(ans, nums[i + k - 1] - nums[i]);\n        }\n        return ans;\n    }\n};"
