      "code": "class Solution {\npublic:\n    void setZeroes(vector<vector<int>>& matrix) {\n        int m = matrix.size(), n = matrix[0].size();\n        vector<bool> rows(m);\n        vector<bool> cols(n);\n        for (int i = 0; i < m; ++i) {\n            for (int j = 0; j < n; ++j) {\n                if (!matrix[i][j]) {\n                    rows[i] = 1;\n                    cols[j] = 1;\n                }\n            }\n        }\n        for (int i = 0; i < m; ++i) {\n            for (int j = 0; j < n; ++j) {\n                if (rows[i] || cols[j]) {\n                    matrix[i][j] = 0;\n                }\n            }\n        }\n    }\n};"
