      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(\\log^2 n)$，空间复杂度 $O(1)$ / Space $O(1)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 0440.K-th Smallest in Lexicographical Order Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0400-0499/0440.K-th%20Smallest%20in%20Lexicographical%20Order/README.md",
      "code": "class Solution {\npublic:\n    int n;\n\n    int findKthNumber(int n, int k) {\n        this->n = n;\n        --k;\n        long long curr = 1;\n        while (k) {\n            int cnt = count(curr);\n            if (k >= cnt) {\n                k -= cnt;\n                ++curr;\n            } else {\n                --k;\n                curr *= 10;\n            }\n        }\n        return (int) curr;\n    }\n\n    int count(long long curr) {\n        long long next = curr + 1;\n        int cnt = 0;\n        while (curr <= n) {\n            cnt += min(n - curr + 1, next - curr);\n            next *= 10;\n            curr *= 10;\n        }\n        return cnt;\n    }\n};"
