      "code": "class Solution {\npublic:\n    vector<int> relativeSortArray(vector<int>& arr1, vector<int>& arr2) {\n        vector<int> cnt(1001);\n        for (int x : arr1) {\n            ++cnt[x];\n        }\n        auto [mi, mx] = minmax_element(arr1.begin(), arr1.end());\n        vector<int> ans;\n        for (int x : arr2) {\n            while (cnt[x]) {\n                ans.push_back(x);\n                --cnt[x];\n            }\n        }\n        for (int x = *mi; x <= *mx; ++x) {\n            while (cnt[x]) {\n                ans.push_back(x);\n                --cnt[x];\n            }\n        }\n        return ans;\n    }\n};"
