  "minimum-absolute-sum-difference": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n \\times \\log n)$，空间复杂度 $O(n)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1818.Minimum Absolute Sum Difference Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1800-1899/1818.Minimum%20Absolute%20Sum%20Difference/README.md",
      "code": "class Solution {\npublic:\n    int minAbsoluteSumDiff(vector<int>& nums1, vector<int>& nums2) {\n        const int mod = 1e9 + 7;\n        vector<int> nums(nums1);\n        sort(nums.begin(), nums.end());\n        int s = 0, n = nums.size();\n        for (int i = 0; i < n; ++i) {\n            s = (s + abs(nums1[i] - nums2[i])) % mod;\n        }\n        int mx = 0;\n        for (int i = 0; i < n; ++i) {\n            int d1 = abs(nums1[i] - nums2[i]);\n            int d2 = 1 << 30;\n            int j = lower_bound(nums.begin(), nums.end(), nums2[i]) - nums.begin();\n            if (j < n) {\n                d2 = min(d2, abs(nums[j] - nums2[i]));\n            }\n            if (j) {\n                d2 = min(d2, abs(nums[j - 1] - nums2[i]));\n            }\n            mx = max(mx, d1 - d2);\n        }\n        return (s - mx + mod) % mod;\n    }\n};"
    }
  ],
