      "code": "class Solution {\npublic:\n    string findDifferentBinaryString(vector<string>& nums) {\n        int n = nums.size();\n        string ans(n, '0');\n        for (int i = 0; i < n; i++) {\n            ans[i] = nums[i][i] == '0' ? '1' : '0';\n        }\n        return ans;\n    }\n};"
