      "code": "class Solution {\npublic:\n    int minimumSum(int num) {\n        vector<int> nums;\n        while (num) {\n            nums.push_back(num % 10);\n            num /= 10;\n        }\n        sort(nums.begin(), nums.end());\n        return 10 * (nums[0] + nums[1]) + nums[2] + nums[3];\n    }\n};"
