      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}\n * };\n */\nclass Solution {\npublic:\n    TreeNode* inorderSuccessor(TreeNode* root, TreeNode* p) {\n        TreeNode* ans = nullptr;\n        while (root) {\n            if (root->val > p->val) {\n                ans = root;\n                root = root->left;\n            } else {\n                root = root->right;\n            }\n        }\n        return ans;\n    }\n};"
