  "longest-substring-with-at-least-k-repeating-characters": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n \\times C)$，空间复杂度 $O(C^2)$ / Space $O(C^2)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 0395.Longest Substring with At Least K Repeating Characters Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0300-0399/0395.Longest%20Substring%20with%20At%20Least%20K%20Repeating%20Characters/README.md",
      "code": "class Solution {\npublic:\n    int longestSubstring(string s, int k) {\n        function<int(int, int)> dfs = [&](int l, int r) -> int {\n            int cnt[26] = {0};\n            for (int i = l; i <= r; ++i) {\n                cnt[s[i] - 'a']++;\n            }\n            char split = 0;\n            for (int i = 0; i < 26; ++i) {\n                if (cnt[i] > 0 && cnt[i] < k) {\n                    split = 'a' + i;\n                    break;\n                }\n            }\n            if (split == 0) {\n                return r - l + 1;\n            }\n            int i = l;\n            int ans = 0;\n            while (i <= r) {\n                while (i <= r && s[i] == split) {\n                    ++i;\n                }\n                if (i >= r) {\n                    break;\n                }\n                int j = i;\n                while (j <= r && s[j] != split) {\n                    ++j;\n                }\n                int t = dfs(i, j - 1);\n                ans = max(ans, t);\n                i = j;\n            }\n            return ans;\n        };\n        return dfs(0, s.size() - 1);\n    }\n};"
    }
  ],
