  "search-suggestions-system": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(L \\times \\log n + m)$，空间复杂度 $O(L)$ / Space $O(L)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1268.Search Suggestions System Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1200-1299/1268.Search%20Suggestions%20System/README.md",
      "code": "class Trie {\npublic:\n    void insert(string& w, int i) {\n        Trie* node = this;\n        for (int j = 0; j < w.size(); ++j) {\n            int idx = w[j] - 'a';\n            if (!node->children[idx]) {\n                node->children[idx] = new Trie();\n            }\n            node = node->children[idx];\n            if (node->v.size() < 3) {\n                node->v.push_back(i);\n            }\n        }\n    }\n\n    vector<vector<int>> search(string& w) {\n        Trie* node = this;\n        int n = w.size();\n        vector<vector<int>> ans(n);\n        for (int i = 0; i < w.size(); ++i) {\n            int idx = w[i] - 'a';\n            if (!node->children[idx]) {\n                break;\n            }\n            node = node->children[idx];\n            ans[i] = move(node->v);\n        }\n        return ans;\n    }\n\nprivate:\n    vector<Trie*> children = vector<Trie*>(26);\n    vector<int> v;\n};\n\nclass Solution {\npublic:\n    vector<vector<string>> suggestedProducts(vector<string>& products, string searchWord) {\n        sort(products.begin(), products.end());\n        Trie* trie = new Trie();\n        for (int i = 0; i < products.size(); ++i) {\n            trie->insert(products[i], i);\n        }\n        vector<vector<string>> ans;\n        for (auto& v : trie->search(searchWord)) {\n            vector<string> t;\n            for (int i : v) {\n                t.push_back(products[i]);\n            }\n            ans.push_back(move(t));\n        }\n        return ans;\n    }\n};"
    }
  ],
