      "code": "class Solution {\npublic:\n    string thousandSeparator(int n) {\n        int cnt = 0;\n        string ans;\n        while (1) {\n            int v = n % 10;\n            n /= 10;\n            ans += to_string(v);\n            if (n == 0) break;\n            if (++cnt == 3) {\n                ans += '.';\n                cnt = 0;\n            }\n        }\n        reverse(ans.begin(), ans.end());\n        return ans;\n    }\n};"
