      "code": "class Solution {\npublic:\n    int maxAbsoluteSum(vector<int>& nums) {\n        int f = 0, g = 0;\n        int ans = 0;\n        for (int& x : nums) {\n            f = max(f, 0) + x;\n            g = min(g, 0) + x;\n            ans = max({ans, f, abs(g)});\n        }\n        return ans;\n    }\n};"
