      "code": "class Solution {\npublic:\n    bool validateStackSequences(vector<int>& pushed, vector<int>& popped) {\n        stack<int> stk;\n        int j = 0;\n        for (int v : pushed) {\n            stk.push(v);\n            while (!stk.empty() && stk.top() == popped[j]) {\n                stk.pop();\n                ++j;\n            }\n        }\n        return j == pushed.size();\n    }\n};"
