  "sum-of-root-to-leaf-binary-numbers": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n)$，空间复杂度 $O(n)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1022.Sum of Root To Leaf Binary Numbers Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1000-1099/1022.Sum%20of%20Root%20To%20Leaf%20Binary%20Numbers/README.md",
      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:\n    int sumRootToLeaf(TreeNode* root) {\n        auto dfs = [&](this auto&& dfs, TreeNode* root, int x) -> int {\n            if (!root) {\n                return 0;\n            }\n            x = x << 1 | root->val;\n            if (root->left == root->right) {\n                return x;\n            }\n            return dfs(root->left, x) + dfs(root->right, x);\n        };\n        return dfs(root, 0);\n    }\n};"
    }
  ],
