      "code": "class Solution {\npublic:\n    int numberOfSubstrings(string s) {\n        int d[3] = {-1, -1, -1};\n        int ans = 0;\n        for (int i = 0; i < s.size(); ++i) {\n            d[s[i] - 'a'] = i;\n            ans += min(d[0], min(d[1], d[2])) + 1;\n        }\n        return ans;\n    }\n};"
