      "code": "class Solution {\npublic:\n    vector<string> buildArray(vector<int>& target, int n) {\n        vector<string> ans;\n        int cur = 1;\n        for (int x : target) {\n            while (cur < x) {\n                ans.push_back(\"Push\");\n                ans.push_back(\"Pop\");\n                ++cur;\n            }\n            ans.push_back(\"Push\");\n            ++cur;\n        }\n        return ans;\n    }\n};"
