      "code": "class Solution {\npublic:\n    bool validPath(int n, vector<vector<int>>& edges, int source, int destination) {\n        vector<int> g[n];\n        vector<bool> vis(n);\n        for (const auto& e : edges) {\n            int u = e[0], v = e[1];\n            g[u].push_back(v);\n            g[v].push_back(u);\n        }\n        function<bool(int)> dfs = [&](int i) -> bool {\n            if (i == destination) {\n                return true;\n            }\n            vis[i] = true;\n            for (int j : g[i]) {\n                if (!vis[j] && dfs(j)) {\n                    return true;\n                }\n            }\n            return false;\n        };\n        return dfs(source);\n    }\n};"
