      "code": "class Solution {\npublic:\n    int missingNumber(vector<int>& nums) {\n        int l = 0, r = nums.size();\n        while (l < r) {\n            int mid = (l + r) >> 1;\n            if (nums[mid] > mid) {\n                r = mid;\n            } else {\n                l = mid + 1;\n            }\n        }\n        return l;\n    }\n};"
