      "code": "class Solution {\npublic:\n    vector<int> findClosestElements(vector<int>& arr, int k, int x) {\n        int l = 0, r = arr.size();\n        while (r - l > k) {\n            if (x - arr[l] <= arr[r - 1] - x) {\n                --r;\n            } else {\n                ++l;\n            }\n        }\n        return vector<int>(arr.begin() + l, arr.begin() + r);\n    }\n};"
