      "code": "class Solution {\npublic:\n    vector<int> findClosestElements(vector<int>& arr, int k, int x) {\n        int left = 0, right = arr.size() - k;\n        while (left < right) {\n            int mid = (left + right) >> 1;\n            if (x - arr[mid] <= arr[mid + k] - x)\n                right = mid;\n            else\n                left = mid + 1;\n        }\n        return vector<int>(arr.begin() + left, arr.begin() + left + k);\n    }\n};"
