      "code": "class Solution {\npublic:\n    int maxScore(string s) {\n        int l = 0, r = count(s.begin(), s.end(), '1');\n        int ans = 0;\n        for (int i = 0; i < s.size() - 1; ++i) {\n            l += (s[i] - '0') ^ 1;\n            r -= s[i] - '0';\n            ans = max(ans, l + r);\n        }\n        return ans;\n    }\n};"
