      "code": "class Solution {\npublic:\n    int timeRequiredToBuy(vector<int>& tickets, int k) {\n        int ans = 0;\n        for (int i = 0; i < tickets.size(); ++i) {\n            ans += min(tickets[i], i <= k ? tickets[k] : tickets[k] - 1);\n        }\n        return ans;\n    }\n};"
