      "code": "class Solution {\npublic:\n    int missingNumber(vector<int>& nums) {\n        int n = nums.size();\n        int ans = n;\n        for (int i = 0; i < n; ++i) {\n            ans ^= (i ^ nums[i]);\n        }\n        return ans;\n    }\n};"
