      "code": "class Solution {\npublic:\n    int maxScore(vector<int>& nums) {\n        int n = nums.size();\n        vector<int> f(n);\n        for (int j = 1; j < n; ++j) {\n            for (int i = 0; i < j; ++i) {\n                f[j] = max(f[j], f[i] + (j - i) * nums[j]);\n            }\n        }\n        return f[n - 1];\n    }\n};"
