      "code": "class Solution {\npublic:\n    int maxScore(vector<int>& nums) {\n        vector<int> stk;\n        for (int i = 0; i < nums.size(); ++i) {\n            while (stk.size() && nums[stk.back()] <= nums[i]) {\n                stk.pop_back();\n            }\n            stk.push_back(i);\n        }\n        int ans = 0, i = 0;\n        for (int j : stk) {\n            ans += (j - i) * nums[j];\n            i = j;\n        }\n        return ans;\n    }\n};"
