      "code": "class Solution {\npublic:\n    int combinationSum4(vector<int>& nums, int target) {\n        int f[target + 1];\n        memset(f, 0, sizeof(f));\n        f[0] = 1;\n        for (int i = 1; i <= target; ++i) {\n            for (int x : nums) {\n                if (i >= x && f[i - x] < INT_MAX - f[i]) {\n                    f[i] += f[i - x];\n                }\n            }\n        }\n        return f[target];\n    }\n};"
