      "code": "// Time:  O(n)\n// Space: O(1)\n\n// greedy, case works\nclass Solution {\npublic:\n    int minFlips(string s) {\n        const int cnt0 = ranges::count(s, '0');\n        const int cnt1 = size(s) - cnt0;\n        return min({\n            cnt0,\n            max(cnt1 - 1, 0),\n            max(cnt1 - (s[0] == '1' ? 1 : 0) - (s.back() == '1' ? 1 : 0), 0)\n        });\n    }\n};"
