      "code": "class Solution {\npublic:\n    vector<string> getFolderNames(vector<string>& names) {\n        unordered_map<string, int> d;\n        for (auto& name : names) {\n            int k = d[name];\n            if (k) {\n                while (d[name + \"(\" + to_string(k) + \")\"]) {\n                    k++;\n                }\n                d[name] = k;\n                name += \"(\" + to_string(k) + \")\";\n            }\n            d[name] = 1;\n        }\n        return names;\n    }\n};"
