  "ip-to-cidr": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Modern C++ reference",
      "complexity": null,
      "license": "MIT",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "kamyu104 C++/ip-to-cidr.cpp",
      "sourceUrl": "https://github.com/kamyu104/LeetCode-Solutions/blob/master/C%2B%2B/ip-to-cidr.cpp",
      "code": "// Time:  O(n)\n// Space: O(1)\n\nclass Solution {\npublic:\n    vector<string> ipToCIDR(string ip, int range) {\n        auto start = ipToInt(ip);\n        vector<string> result;\n        while (range > 0) {\n            auto mask = max(33 - bitLength(start & ~(start - 1)),\n                            33 - bitLength(range));\n            result.emplace_back(intToIP(start) + \"/\" + to_string(mask));\n            start += 1 << (32 - mask);\n            range -= 1 << (32 - mask);\n        }\n        return result;\n    }\n\nprivate:\n    uint32_t ipToInt(const string& ip) {\n        uint32_t result = 0;\n        for (const auto& n : split(ip, '.')) {\n            result = 256 * result + stoi(n);\n        }\n        return result;\n    }\n\n    string intToIP(uint32_t n) {\n        string ip;\n        for (const auto& i : {24, 16, 8, 0}) {\n            ip += to_string((n >> i) % 256);\n            ip += \".\";\n        }\n        ip.pop_back();\n        return ip;\n    }\n                \n    vector<string> split(const string& s, const char delim) {\n        vector<string> tokens;\n        stringstream ss(s);\n        string token;\n        while (getline(ss, token, delim)) {\n            tokens.emplace_back(token);\n        }\n        return tokens;\n    }\n    \n    uint32_t bitLength(uint32_t n) {\n        uint32_t left = 1, right = 32;\n        while (left <= right) {\n            auto mid = left + (right - left) / 2;\n            if ((1 << mid) > n) {\n                right = mid - 1;\n            } else {\n                left = mid + 1;\n            }\n        }\n        return left;\n    }\n};"
    }
  ],
