      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/2300-2399/2343.Query%20Kth%20Smallest%20Trimmed%20Number/README.md",
      "code": "class Solution {\npublic:\n    vector<int> smallestTrimmedNumbers(vector<string>& nums, vector<vector<int>>& queries) {\n        int n = nums.size();\n        vector<pair<string, int>> t(n);\n        vector<int> ans;\n        for (auto& q : queries) {\n            int k = q[0], trim = q[1];\n            for (int j = 0; j < n; ++j) {\n                t[j] = {nums[j].substr(nums[j].size() - trim), j};\n            }\n            sort(t.begin(), t.end());\n            ans.push_back(t[k - 1].second);\n        }\n        return ans;\n    }\n};"
