      "code": "class Solution {\npublic:\n    int minimumNumbers(int num, int k) {\n        if (num == 0) return 0;\n        for (int i = 1; i <= num; ++i) {\n            int t = num - k * i;\n            if (t >= 0 && t % 10 == 0) return i;\n        }\n        return -1;\n    }\n};"
