  "maximize-value-of-function-in-a-ball-passing-game": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time 为 $O(k)$，显然会超时 / Space $O(n \\times \\log k)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 2836.Maximize Value of Function in a Ball Passing Game Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/2800-2899/2836.Maximize%20Value%20of%20Function%20in%20a%20Ball%20Passing%20Game/README.md",
      "code": "class Solution {\npublic:\n    long long getMaxFunctionValue(vector<int>& receiver, long long k) {\n        int n = receiver.size(), m = 64 - __builtin_clzll(k);\n        int f[n][m];\n        long long g[n][m];\n        for (int i = 0; i < n; ++i) {\n            f[i][0] = receiver[i];\n            g[i][0] = i;\n        }\n        for (int j = 1; j < m; ++j) {\n            for (int i = 0; i < n; ++i) {\n                f[i][j] = f[f[i][j - 1]][j - 1];\n                g[i][j] = g[i][j - 1] + g[f[i][j - 1]][j - 1];\n            }\n        }\n        long long ans = 0;\n        for (int i = 0; i < n; ++i) {\n            int p = i;\n            long long t = 0;\n            for (int j = 0; j < m; ++j) {\n                if (k >> j & 1) {\n                    t += g[p][j];\n                    p = f[p][j];\n                }\n            }\n            ans = max(ans, p + t);\n        }\n        return ans;\n    }\n};"
    }
  ],
