  "solve-the-equation": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Modern C++ reference",
      "complexity": null,
      "license": "MIT",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "kamyu104 C++/solve-the-equation.cpp",
      "sourceUrl": "https://github.com/kamyu104/LeetCode-Solutions/blob/master/C%2B%2B/solve-the-equation.cpp",
      "code": "// Time:  O(n)\n// Space: O(n)\n\nclass Solution {\npublic:\n    string solveEquation(string equation) {\n        auto a = 0, b = 0;\n        auto side = 1;\n        int submatches[] = { 1, 2, 3, 4 };\n        auto e = regex(\"(=)|([-+]?)(\\\\d*)(x?)\");\n        for (regex_token_iterator<string::iterator> it(equation.begin(), equation.end(), e, submatches), end;\n             it != end;) {\n            auto eq = (it++)->str();\n            auto sign = (it++)->str();\n            auto num = (it++)->str();\n            auto isx = (it++)->str();\n            if (!eq.empty()) {\n                side = -1;\n            } else if (!isx.empty()) {\n                a += side * stoi(sign + \"1\") * stoi(num.empty() ? \"1\" : num);\n            } else if (!num.empty()) {\n                b -= side * stoi(sign + num);\n            }\n        }\n        return a != 0 ? \"x=\" + to_string(b / a) : b != 0 ? \"No solution\" : \"Infinite solutions\";\n    }\n};\n\n// Time:  O(n)\n// Space: O(n)\nclass Solution2 {\npublic:\n    string solveEquation(string equation) {\n        equation = regex_replace(equation, regex(\"(^|[+=-])x\"), \"$011x\");\n\n        auto pos = equation.find('=');\n        auto l = coef(equation.substr(0, pos));\n        auto r = coef(equation.substr(pos + 1));\n\n        auto a = l.first - r.first;\n        auto b = r.second - l.second;\n\n        return a != 0 ? \"x=\" + to_string(b / a) : b != 0 ? \"No solution\" : \"Infinite solutions\";\n    }\n\nprivate:\n    pair<int, int> coef(string s) {\n        auto a = 0, b = 0;\n        auto e = regex(\"(^|[+-])\\\\d+x?\");\n        for (regex_token_iterator<string::iterator> it(s.begin(), s.end(), e), end;\n             it != end; ++it) {\n            (it->str().back() == 'x' ? a : b) += stoi(*it);\n        }\n        return {a, b};\n    } \n};"
    }
  ],
