      "code": "class Solution {\npublic:\n    vector<int> findBuildings(vector<int>& heights) {\n        vector<int> ans;\n        int mx = 0;\n        for (int i = heights.size() - 1; ~i; --i) {\n            if (heights[i] > mx) {\n                ans.push_back(i);\n                mx = heights[i];\n            }\n        }\n        reverse(ans.begin(), ans.end());\n        return ans;\n    }\n};"
