  "longest-balanced-substring-ii": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n)$，空间复杂度 $O(n)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 3714.Longest Balanced Substring II Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/3700-3799/3714.Longest%20Balanced%20Substring%20II/README.md",
      "code": "class Solution {\npublic:\n    int longestBalanced(string s) {\n        int x = calc1(s);\n        int y = max({calc2(s, 'a', 'b'), calc2(s, 'b', 'c'), calc2(s, 'a', 'c')});\n        int z = calc3(s);\n        return max({x, y, z});\n    }\n\nprivate:\n    int calc1(const string& s) {\n        int res = 0;\n        int i = 0, n = s.size();\n        while (i < n) {\n            int j = i + 1;\n            while (j < n && s[j] == s[i]) {\n                ++j;\n            }\n            res = max(res, j - i);\n            i = j;\n        }\n        return res;\n    }\n\n    int calc2(const string& s, char a, char b) {\n        int res = 0;\n        int i = 0, n = s.size();\n        while (i < n) {\n            while (i < n && s[i] != a && s[i] != b) {\n                ++i;\n            }\n\n            unordered_map<int, int> pos;\n            pos[0] = i - 1;\n\n            int d = 0;\n            while (i < n && (s[i] == a || s[i] == b)) {\n                d += (s[i] == a) ? 1 : -1;\n                auto it = pos.find(d);\n                if (it != pos.end()) {\n                    res = max(res, i - it->second);\n                } else {\n                    pos[d] = i;\n                }\n                i++;\n            }\n        }\n        return res;\n    }\n\n    static long long f(int x, int y) {\n        return ((long long) (x + 100000) << 20) | (long long) (y + 100000);\n    }\n\n    int calc3(const string& s) {\n        unordered_map<long long, int> pos;\n        pos[f(0, 0)] = -1;\n\n        int cnt[3] = {0, 0, 0};\n        int res = 0;\n\n        for (int i = 0; i < (int) s.size(); i++) {\n            char c = s[i];\n            ++cnt[c - 'a'];\n            int x = cnt[0] - cnt[1];\n            int y = cnt[1] - cnt[2];\n            long long k = f(x, y);\n\n            auto it = pos.find(k);\n            if (it != pos.end()) {\n                res = max(res, i - it->second);\n            } else {\n                pos[k] = i;\n            }\n        }\n        return res;\n    }\n};"
    }
  ],
