      "code": "class Solution {\npublic:\n    bool areOccurrencesEqual(string s) {\n        vector<int> cnt(26);\n        for (char c : s) {\n            ++cnt[c - 'a'];\n        }\n        int v = 0;\n        for (int x : cnt) {\n            if (x == 0) {\n                continue;\n            }\n            if (v && v != x) {\n                return false;\n            }\n            v = x;\n        }\n        return true;\n    }\n};"
