  "minimum-cost-path-with-edge-reversals": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n + m \\times \\log m)$，空间复杂度 $O(n + m)$ / Space $O(n + m)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 3650.Minimum Cost Path with Edge Reversals Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/3600-3699/3650.Minimum%20Cost%20Path%20with%20Edge%20Reversals/README.md",
      "code": "class Solution {\npublic:\n    int minCost(int n, vector<vector<int>>& edges) {\n        using pii = pair<int, int>;\n        vector<vector<pii>> g(n);\n        for (auto& e : edges) {\n            int u = e[0], v = e[1], w = e[2];\n            g[u].push_back({v, w});\n            g[v].push_back({u, w * 2});\n        }\n\n        const int inf = INT_MAX / 2;\n        vector<int> dist(n, inf);\n        dist[0] = 0;\n\n        priority_queue<pii, vector<pii>, greater<pii>> pq;\n        pq.push({0, 0});\n\n        while (!pq.empty()) {\n            auto [d, u] = pq.top();\n            pq.pop();\n            if (d > dist[u]) {\n                continue;\n            }\n            if (u == n - 1) {\n                return d;\n            }\n\n            for (auto& [v, w] : g[u]) {\n                int nd = d + w;\n                if (nd < dist[v]) {\n                    dist[v] = nd;\n                    pq.push({nd, v});\n                }\n            }\n        }\n        return -1;\n    }\n};"
    }
  ],
