  "boolean-evaluation-lcci": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": null,
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 08.14.Boolean Evaluation Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/lcci/08.14.Boolean%20Evaluation/README.md",
      "code": "class Solution {\npublic:\n    unordered_map<string, vector<int>> memo;\n\n    int countEval(string s, int result) {\n        vector<int> ans = dfs(s);\n        return result == 0 || result == 1 ? ans[result] : 0;\n    }\n\n    vector<int> dfs(string s) {\n        if (memo.count(s)) return memo[s];\n        vector<int> res(2);\n        if (s.size() == 1) {\n            res[s[0] - '0'] = 1;\n            return res;\n        }\n        for (int k = 0; k < s.size(); ++k) {\n            if (s[k] == '0' || s[k] == '1') continue;\n            vector<int> left = dfs(s.substr(0, k));\n            vector<int> right = dfs(s.substr(k + 1, s.size() - k));\n            for (int i = 0; i < 2; ++i) {\n                for (int j = 0; j < 2; ++j) {\n                    int v = 0;\n                    if (s[k] == '&')\n                        v = i & j;\n                    else if (s[k] == '|')\n                        v = i | j;\n                    else if (s[k] == '^')\n                        v = i ^ j;\n                    res[v] += left[i] * right[j];\n                }\n            }\n        }\n        memo[s] = res;\n        return res;\n    }\n};"
    }
  ],
