  "circus-tower-lcci": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time $O(n^2)$ / Space $O(n)$",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 17.08.Circus Tower Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/lcci/17.08.Circus%20Tower/README.md",
      "code": "class BinaryIndexedTree {\npublic:\n    BinaryIndexedTree(int _n)\n        : n(_n)\n        , c(_n + 1) {}\n\n    void update(int x, int val) {\n        while (x <= n) {\n            c[x] = max(c[x], val);\n            x += x & -x;\n        }\n    }\n\n    int query(int x) {\n        int s = 0;\n        while (x > 0) {\n            s = max(s, c[x]);\n            x -= x & -x;\n        }\n        return s;\n    }\n\nprivate:\n    int n;\n    vector<int> c;\n};\n\nclass Solution {\npublic:\n    int bestSeqAtIndex(vector<int>& height, vector<int>& weight) {\n        int n = height.size();\n        vector<pair<int, int>> people;\n        for (int i = 0; i < n; ++i) {\n            people.emplace_back(height[i], weight[i]);\n        }\n        sort(people.begin(), people.end(), [](const pair<int, int>& a, const pair<int, int>& b) {\n            if (a.first == b.first) {\n                return a.second > b.second;\n            }\n            return a.first < b.first;\n        });\n        vector<int> alls = weight;\n        sort(alls.begin(), alls.end());\n        alls.erase(unique(alls.begin(), alls.end()), alls.end());\n        BinaryIndexedTree tree(alls.size());\n        int ans = 1;\n        for (auto& [_, w] : people) {\n            int x = lower_bound(alls.begin(), alls.end(), w) - alls.begin() + 1;\n            int t = tree.query(x - 1) + 1;\n            ans = max(ans, t);\n            tree.update(x, t);\n        }\n        return ans;\n    }\n};"
    }
  ],
  "alien-dictionary": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time 为 $O(n^3)$；但是我们发现其实比较相邻的两个单词就可以了，比如 $a",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 0269.Alien Dictionary Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0200-0299/0269.Alien%20Dictionary/README.md",
      "code": "class Solution {\npublic:\n    string alienOrder(vector<string>& words) {\n        vector<vector<bool>> g(26, vector<bool>(26));\n        vector<bool> s(26);\n        int cnt = 0;\n        int n = words.size();\n        for (int i = 0; i < n - 1; ++i) {\n            for (char c : words[i]) {\n                if (cnt == 26) break;\n                c -= 'a';\n                if (!s[c]) {\n                    ++cnt;\n                    s[c] = true;\n                }\n            }\n            int m = words[i].size();\n            for (int j = 0; j < m; ++j) {\n                if (j >= words[i + 1].size()) return \"\";\n                char c1 = words[i][j], c2 = words[i + 1][j];\n                if (c1 == c2) continue;\n                if (g[c2 - 'a'][c1 - 'a']) return \"\";\n                g[c1 - 'a'][c2 - 'a'] = true;\n                break;\n            }\n        }\n        for (char c : words[n - 1]) {\n            if (cnt == 26) break;\n            c -= 'a';\n            if (!s[c]) {\n                ++cnt;\n                s[c] = true;\n            }\n        }\n        vector<int> indegree(26);\n        for (int i = 0; i < 26; ++i)\n            for (int j = 0; j < 26; ++j)\n                if (i != j && s[i] && s[j] && g[i][j])\n                    ++indegree[j];\n        queue<int> q;\n        for (int i = 0; i < 26; ++i)\n            if (s[i] && indegree[i] == 0)\n                q.push(i);\n        string ans = \"\";\n        while (!q.empty()) {\n            int t = q.front();\n            ans += (t + 'a');\n            q.pop();\n            for (int i = 0; i < 26; ++i)\n                if (i != t && s[i] && g[t][i])\n                    if (--indegree[i] == 0)\n                        q.push(i);\n        }\n        return ans.size() < cnt ? \"\" : ans;\n    }\n};"
    }
  ],
