      "code": "class Solution {\npublic:\n    bool validWordSquare(vector<string>& words) {\n        int m = words.size();\n        for (int i = 0; i < m; ++i) {\n            int n = words[i].size();\n            for (int j = 0; j < n; ++j) {\n                if (j >= m || i >= words[j].size() || words[i][j] != words[j][i]) {\n                    return false;\n                }\n            }\n        }\n        return true;\n    }\n};"
