      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/0600-0699/0650.2%20Keys%20Keyboard/README.md",
      "code": "class Solution {\npublic:\n    vector<int> f;\n\n    int minSteps(int n) {\n        f.assign(n + 1, -1);\n        return dfs(n);\n    }\n\n    int dfs(int n) {\n        if (n == 1) return 0;\n        if (f[n] != -1) return f[n];\n        int ans = n;\n        for (int i = 2; i * i <= n; ++i) {\n            if (n % i == 0) {\n                ans = min(ans, dfs(n / i) + i);\n            }\n        }\n        f[n] = ans;\n        return ans;\n    }\n};"
