  "design-skiplist": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": "Time 不超过 / Space 是",
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1206.Design Skiplist Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1200-1299/1206.Design%20Skiplist/README.md",
      "code": "struct Node {\n    int val;\n    vector<Node*> next;\n    Node(int v, int level)\n        : val(v)\n        , next(level, nullptr) {}\n};\n\nclass Skiplist {\npublic:\n    const int p = RAND_MAX / 4;\n    const int maxLevel = 32;\n    Node* head;\n    int level;\n\n    Skiplist() {\n        head = new Node(-1, maxLevel);\n        level = 0;\n    }\n\n    bool search(int target) {\n        Node* curr = head;\n        for (int i = level - 1; ~i; --i) {\n            curr = findClosest(curr, i, target);\n            if (curr->next[i] && curr->next[i]->val == target) return true;\n        }\n        return false;\n    }\n\n    void add(int num) {\n        Node* curr = head;\n        int lv = randomLevel();\n        Node* node = new Node(num, lv);\n        level = max(level, lv);\n        for (int i = level - 1; ~i; --i) {\n            curr = findClosest(curr, i, num);\n            if (i < lv) {\n                node->next[i] = curr->next[i];\n                curr->next[i] = node;\n            }\n        }\n    }\n\n    bool erase(int num) {\n        Node* curr = head;\n        bool ok = false;\n        for (int i = level - 1; ~i; --i) {\n            curr = findClosest(curr, i, num);\n            if (curr->next[i] && curr->next[i]->val == num) {\n                curr->next[i] = curr->next[i]->next[i];\n                ok = true;\n            }\n        }\n        while (level > 1 && !head->next[level - 1]) --level;\n        return ok;\n    }\n\n    Node* findClosest(Node* curr, int level, int target) {\n        while (curr->next[level] && curr->next[level]->val < target) curr = curr->next[level];\n        return curr;\n    }\n\n    int randomLevel() {\n        int lv = 1;\n        while (lv < maxLevel && rand() < p) ++lv;\n        return lv;\n    }\n};\n\n/**\n * Your Skiplist object will be instantiated and called as such:\n * Skiplist* obj = new Skiplist();\n * bool param_1 = obj->search(target);\n * obj->add(num);\n * bool param_3 = obj->erase(num);\n */"
    }
  ],
  "minimum-number-of-flips-to-convert-binary-matrix-to-zero-matrix": [
    {
      "language": "C++",
      "status": "Reference",
      "provenance": "external-reference",
      "approachTitle": "Reference",
      "complexity": null,
      "license": "CC-BY-SA-4.0",
      "modified": false,
      "submittedAt": null,
      "runtime": null,
      "memory": null,
      "sourceTitle": "Doocs 1284.Minimum Number of Flips to Convert Binary Matrix to Zero Matrix Reference",
      "sourceUrl": "https://github.com/doocs/leetcode/blob/main/solution/1200-1299/1284.Minimum%20Number%20of%20Flips%20to%20Convert%20Binary%20Matrix%20to%20Zero%20Matrix/README.md",
      "code": "class Solution {\npublic:\n    int minFlips(vector<vector<int>>& mat) {\n        int m = mat.size(), n = mat[0].size();\n        int state = 0;\n        for (int i = 0; i < m; ++i)\n            for (int j = 0; j < n; ++j)\n                if (mat[i][j])\n                    state |= (1 << (i * n + j));\n        queue<int> q{{state}};\n        unordered_set<int> vis{{state}};\n        int ans = 0;\n        vector<int> dirs = {0, -1, 0, 1, 0, 0};\n        while (!q.empty()) {\n            for (int t = q.size(); t; --t) {\n                state = q.front();\n                if (state == 0) return ans;\n                q.pop();\n                for (int i = 0; i < m; ++i) {\n                    for (int j = 0; j < n; ++j) {\n                        int nxt = state;\n                        for (int k = 0; k < 5; ++k) {\n                            int x = i + dirs[k], y = j + dirs[k + 1];\n                            if (x < 0 || x >= m || y < 0 || y >= n) continue;\n                            if ((nxt & (1 << (x * n + y))) != 0)\n                                nxt -= 1 << (x * n + y);\n                            else\n                                nxt |= 1 << (x * n + y);\n                        }\n                        if (!vis.count(nxt)) {\n                            vis.insert(nxt);\n                            q.push(nxt);\n                        }\n                    }\n                }\n            }\n            ++ans;\n        }\n        return -1;\n    }\n};"
    }
  ],
