      "code": "class Solution {\npublic:\n    int findUnsortedSubarray(vector<int>& nums) {\n        const int inf = 1e9;\n        int n = nums.size();\n        int l = -1, r = -1;\n        int mi = inf, mx = -inf;\n        for (int i = 0; i < n; ++i) {\n            if (mx > nums[i]) {\n                r = i;\n            } else {\n                mx = nums[i];\n            }\n            if (mi < nums[n - i - 1]) {\n                l = n - i - 1;\n            } else {\n                mi = nums[n - i - 1];\n            }\n        }\n        return r == -1 ? 0 : r - l + 1;\n    }\n};"
